import React, { useState, useMemo, useCallback } from "react";
import "./InternalPortal.css";
import {
  Box,
  Typography,
  Grid,
  Card,
  CardContent,
  Button,
  Drawer,
  TextField,
  LinearProgress,
  Snackbar,
  Alert,
  IconButton,
  InputAdornment,
  Tabs,
  Tab,
  Modal,
  Avatar,
  Switch,
  FormControlLabel,
  ThemeProvider,
  createTheme,
  Chip,
} from "@mui/material";

import { Close, Search, Brightness4, Brightness7 } from "@mui/icons-material";
import { DragDropContext, Droppable, Draggable } from "react-beautiful-dnd";

/* ================= CONSTANTS ================= */

const ROLES = { EMPLOYEE: "Employee", MANAGER: "Manager", HR: "HR" };

const STAGES = [
  "Applied",
  "Manager Review",
  "Technical Panel",
  "HR Discussion",
  "Selected",
  "Rejected"
];

/* ================= MOCK USER ================= */

const currentUser = {
  id: "EMP101",
  name: "Sreekanth",
  role: ROLES.MANAGER,
  skills: ["React", "Redux", "SQL", "CSS", "MUI"],
  experience: 2,
};

/* ================= MOCK JOBS ================= */

const initialJobs = [
  {
    id: 1,
    title: "Frontend Engineer",
    company: "Abhishyandh Global Solutions",
    companyLogo: "https://via.placeholder.com/50",
    loc: "Hyderabad",
    type: "Full Time",
    salary: "₹8-12 LPA",
    minExperience: 1,
    postedDate: new Date("2026-02-01"),
    status: "Open",
    desc: "Build scalable UI systems using React, Redux, and MUI.",
    coreSkills: ["React", "Redux", "MUI"],
    responsibilities: [
      "Develop responsive UIs",
      "Maintain component library",
      "Ensure cross-browser compatibility"
    ],
    requirements: ["React 2+ years", "Redux", "MUI", "CSS/HTML proficiency"],
    benefits: ["Health insurance", "Remote options", "Annual bonus"],
    applicants: []
  },

  {
    id: 2,
    title: "Backend Node.js Developer",
    company: "Abhishyandh Global Solutions",
    companyLogo: "https://via.placeholder.com/50",
    loc: "Hyderabad",
    type: "Full Time",
    salary: "₹14-18 LPA",
    minExperience: 2,
    postedDate: new Date("2026-01-25"),
    status: "Open",
    desc: "Design and build scalable REST APIs and microservices.",
    coreSkills: ["Node.js", "Express", "MongoDB"],
    responsibilities: [
      "Develop REST APIs",
      "Database optimization",
      "Ensure security"
    ],
    requirements: ["Node.js 2+ years", "MongoDB", "REST APIs", "Docker experience"],
    benefits: ["PF", "Medical coverage", "Flexible hours"],
    applicants: []
  }
];

/* ================= HELPERS ================= */

const skillColor = (percent) =>
  percent >= 80 ? "#4caf50" : percent >= 50 ? "#ff9800" : "#f44336";

/* ================= KPI CARD ================= */

const KpiCard = ({ label, value }) => (
  <Card sx={{ p: 3, textAlign: "center", borderRadius: 3 }}>
    <Typography variant="h6">{value}</Typography>
    <Typography variant="caption">{label}</Typography>
  </Card>
);

/* ================= JOB CARD ================= */

const JobCard = ({ job, skillMatch, onClick }) => (
  <Card
    onClick={onClick}
    sx={{
      cursor: "pointer",
      transition: "0.3s",
      "&:hover": { boxShadow: 6 },
    }}
  >
    <CardContent>
      <Box display="flex" gap={2}>
        <Avatar src={job.companyLogo} />

        <Box>
          <Typography variant="h6">{job.title}</Typography>

          <Typography color="textSecondary">
            {job.company} • {job.loc}
          </Typography>

          <Typography variant="caption">
            Posted: {job.postedDate.toDateString()}
          </Typography>
        </Box>
      </Box>

      <Box mt={1}>
        <LinearProgress
          variant="determinate"
          value={skillMatch}
          sx={{
            height: 8,
            borderRadius: 5,
            "& .MuiLinearProgress-bar": {
              backgroundColor: skillColor(skillMatch)
            }
          }}
        />

        <Typography variant="caption">
          {skillMatch}% skill match
        </Typography>
      </Box>

      <Box mt={1}>
        {job.coreSkills.map((s) => (
          <Chip key={s} label={s} size="small" sx={{ mr: 0.5, mt: 0.5 }} />
        ))}
      </Box>
    </CardContent>
  </Card>
);

/* ================= MAIN COMPONENT ================= */

export default function InternalPortal() {

  const [jobs, setJobs] = useState(initialJobs);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [selectedJob, setSelectedJob] = useState(null);
  const [tab, setTab] = useState(0);

  const [resumeFile, setResumeFile] = useState(null);
  const [coverLetter, setCoverLetter] = useState("");

  const [snackbar, setSnackbar] = useState({
    open: false,
    msg: "",
    sev: "success"
  });

  const [darkMode, setDarkMode] = useState(false);
  const [search, setSearch] = useState("");

  const theme = useMemo(
    () =>
      createTheme({
        palette: { mode: darkMode ? "dark" : "light" }
      }),
    [darkMode]
  );

  const skillMatch = useCallback(
    (job) =>
      Math.round(
        (job.coreSkills.filter((s) =>
          currentUser.skills.includes(s)
        ).length / job.coreSkills.length) * 100
      ),
    []
  );

  const filteredJobs = useMemo(
    () =>
      jobs
        .filter(
          (j) =>
            j.title.toLowerCase().includes(search.toLowerCase()) ||
            j.company.toLowerCase().includes(search.toLowerCase())
        )
        .sort((a, b) => skillMatch(b) - skillMatch(a)),
    [jobs, search, skillMatch]
  );

  const totalApplicants = jobs.reduce(
    (a, j) => a + (j.applicants?.length || 0),
    0
  );

  const myApplications = jobs.filter((j) =>
    j.applicants?.some((a) => a.name === currentUser.name)
  ).length;

  /* ================= APPLY ================= */

  const applyJob = () => {

    if (!resumeFile)
      return setSnackbar({
        open: true,
        msg: "Upload your resume first",
        sev: "error"
      });

    const applicant = {
      name: currentUser.name,
      status: "Applied",
      resume: resumeFile.name,
      cover: coverLetter
    };

    setJobs((prev) =>
      prev.map((j) =>
        j.id === selectedJob.id
          ? { ...j, applicants: [...j.applicants, applicant] }
          : j
      )
    );

    setSnackbar({
      open: true,
      msg: "Applied Successfully!",
      sev: "success"
    });

    setDrawerOpen(false);
  };

  /* ================= UI ================= */

  return (
    <ThemeProvider theme={theme}>
      <Box p={3} sx={{ maxWidth: "1200px", margin: "auto" }}>

        <Typography variant="h4" mb={3}>
          Internal Job Portal
        </Typography>

        {/* KPI CARDS */}

        <Grid container spacing={2} mb={3}>

          <Grid item xs={12} md={4}>
            <KpiCard label="Open Positions" value={jobs.length} />
          </Grid>

          <Grid item xs={12} md={4}>
            <KpiCard label="Total Applicants" value={totalApplicants} />
          </Grid>

          <Grid item xs={12} md={4}>
            <KpiCard label="Your Applications" value={myApplications} />
          </Grid>

        </Grid>

        {/* SEARCH BAR */}

        <Box mb={3}>

          <TextField
            fullWidth
            placeholder="Search jobs"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <Search />
                </InputAdornment>
              )
            }}
          />

        </Box>

        {/* JOB CARDS */}

        <Grid container spacing={4}>

          {filteredJobs.map((job) => (

            <Grid item xs={12} md={6} key={job.id}>

              <JobCard
                job={job}
                skillMatch={skillMatch(job)}
                onClick={() => {
                  setSelectedJob(job);
                  setDrawerOpen(true);
                  setTab(0);
                }}
              />

            </Grid>

          ))}

        </Grid>

        {/* ================= JOB DRAWER ================= */}

        <Drawer
          anchor="right"
          open={drawerOpen}
          onClose={() => setDrawerOpen(false)}
          PaperProps={{ sx: { width: 600, p: 3 } }}
        >

          {selectedJob && (

            <>

              <Box display="flex" justifyContent="space-between">

                <Typography variant="h5">
                  {selectedJob.title}
                </Typography>

                <IconButton onClick={() => setDrawerOpen(false)}>
                  <Close />
                </IconButton>

              </Box>

              <Tabs
                value={tab}
                onChange={(e, v) => setTab(v)}
                variant="fullWidth"
                sx={{ mb: 3 }}
              >
                <Tab label="Description" />
                <Tab label="Apply" />
                <Tab label="Applicants" />
              </Tabs>

              {/* DESCRIPTION */}

              {tab === 0 && (

                <Box sx={{ lineHeight: 1.8 }}>

                  <Typography mb={2}>
                    {selectedJob.desc}
                  </Typography>

                  <Typography fontWeight="bold">
                    Responsibilities:
                  </Typography>

                  <ul>
                    {selectedJob.responsibilities.map((item, i) => (
                      <li key={i}>{item}</li>
                    ))}
                  </ul>

                  <Typography fontWeight="bold">
                    Requirements:
                  </Typography>

                  <ul>
                    {selectedJob.requirements.map((item, i) => (
                      <li key={i}>{item}</li>
                    ))}
                  </ul>

                  <Typography fontWeight="bold">
                    Benefits:
                  </Typography>

                  <ul>
                    {selectedJob.benefits.map((item, i) => (
                      <li key={i}>{item}</li>
                    ))}
                  </ul>

                </Box>

              )}

              {/* APPLY */}

              {tab === 1 && (

                <Box display="flex" flexDirection="column" gap={2}>

                  <TextField
                    type="file"
                    onChange={(e) =>
                      setResumeFile(e.target.files[0])
                    }
                  />

                  <TextField
                    label="Cover Letter"
                    multiline
                    rows={4}
                    value={coverLetter}
                    onChange={(e) =>
                      setCoverLetter(e.target.value)
                    }
                  />

                  <Button
                    variant="contained"
                    onClick={applyJob}
                  >
                    Apply
                  </Button>

                </Box>

              )}

              {/* APPLICANTS */}

              {tab === 2 && (

                <Box display="flex" gap={2} mt={2}>

                  {STAGES.map((stage) => (

                    <Box
                      key={stage}
                      sx={{
                        width: 140,
                        minHeight: 120,
                        bgcolor: "#f4f6f9",
                        borderRadius: 2,
                        p: 1
                      }}
                    >

                      <Typography
                        variant="subtitle2"
                        fontWeight="bold"
                        mb={1}
                      >
                        {stage}
                      </Typography>

                    </Box>

                  ))}

                </Box>

              )}

            </>

          )}

        </Drawer>

      </Box>
    </ThemeProvider>
  );
}
